sql:
SELECT user_id, movie_id, AVG(playback_position) AS Average_Playback_Position
FROM user_history
GROUP BY user_id, movie_id;

SELECT * 
FROM user_engagement 
WHERE user_id = 1;

SELECT AVG(ratings_count) AS average_ratings_per_user
FROM (
  SELECT user_id, COUNT(*) AS ratings_count
  FROM ratings
  GROUP BY user_id
) AS subquery;

SELECT 
    (SELECT COUNT(DISTINCT user_id) FROM users) AS total_users,
    (SELECT COUNT(DISTINCT movie_id) FROM movies) AS total_movies;

SELECT AVG(server_load) AS average_server_load, AVG(database_query_time) AS average_database_query_time
FROM system_performance
WHERE server_load IS NOT NULL AND database_query_time IS NOT NULL;

